import { useStripe } from '@stripe/stripe-react-native';
import { useState } from 'react';

export default function CheckoutScreen({ cartItems }) {
  const { initPaymentSheet, presentPaymentSheet } = useStripe();
  const [loading, setLoading] = useState(false);

  const handleCheckout = async () => {
    setLoading(true);
    try {
      // 1. Appel backend pour créer PaymentIntent
      const response = await fetch('https://api.example.com/create-payment-intent', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ items: cartItems })
      });
      const { clientSecret, publishableKey } = await response.json();

      // 2. Initialiser PaymentSheet
      const { error: initError } = await initPaymentSheet({
        paymentIntentClientSecret: clientSecret,
        merchantDisplayName: 'Ma Boutique',
      });
      if (initError) throw new Error(initError.message);

      // 3. Présenter le PaymentSheet
      const { error: presentError } = await presentPaymentSheet();
      if (presentError) throw new Error(presentError.message);

      alert('✅ Paiement réussi ! Commande confirmée.');
    } catch (error) {
      alert(`Erreur: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Button title="Payer" onPress={handleCheckout} disabled={loading} />
  );
}
